"use client";

import { useEffect, useState } from "react";
import { motion, useSpring, useMotionValue } from "framer-motion";
import { cn } from "@/lib/utils";

export function CustomCursor() {
  const [isHovered, setIsHovered] = useState(false);
  const cursorX = useMotionValue(-100);
  const cursorY = useMotionValue(-100);
  
  const springConfig = { damping: 25, stiffness: 700 };
  const cursorXSpring = useSpring(cursorX, springConfig);
  const cursorYSpring = useSpring(cursorY, springConfig);

  useEffect(() => {
    const moveCursor = (e: MouseEvent) => {
      cursorX.set(e.clientX);
      cursorY.set(e.clientY);
    };

    const handleMouseOver = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (
        target.tagName.toLowerCase() === "a" ||
        target.tagName.toLowerCase() === "button" ||
        target.closest("a") ||
        target.closest("button") ||
        target.classList.contains("cursor-pointer")
      ) {
        setIsHovered(true);
      } else {
        setIsHovered(false);
      }
    };

    window.addEventListener("mousemove", moveCursor);
    window.addEventListener("mouseover", handleMouseOver);

    return () => {
      window.removeEventListener("mousemove", moveCursor);
      window.removeEventListener("mouseover", handleMouseOver);
    };
  }, [cursorX, cursorY]);

  return (
    <>
      <motion.div
        className={cn(
          "fixed left-0 top-0 w-4 h-4 rounded-full bg-accent mix-blend-difference pointer-events-none z-[9999]",
          isHovered ? "w-8 h-8 -translate-x-1/2 -translate-y-1/2" : "-translate-x-1/2 -translate-y-1/2"
        )}
        style={{
          x: cursorXSpring,
          y: cursorYSpring,
        }}
        transition={{
            type: "spring",
            stiffness: 500,
            damping: 28
        }}
      />
      <motion.div 
        className={cn(
            "fixed left-0 top-0 w-8 h-8 border border-accent rounded-full pointer-events-none z-[9998] transition-opacity duration-300",
            isHovered ? "opacity-0" : "opacity-100"
        )}
        style={{
            x: cursorXSpring,
            y: cursorYSpring,
            translateX: "-50%",
            translateY: "-50%"
        }}
        transition={{
            type: "spring",
            stiffness: 250,
            damping: 20,
            mass: 0.5
        }}
      />
    </>
  );
}
